  standalone: true,
  imports: [RippleDirective],
  template: `
    <div
      nRipple
      class="bg-muted text-muted-foreground flex h-24 w-48 cursor-pointer items-center justify-center rounded-lg text-sm font-medium select-none"
    >
      Clique aqui
    </div>
  `,
})
export class RippleDefaultDemo {}

import { Component } from '@angular/core';
import { ButtonComponent } from '../../button/button.component';
import { RippleDirective } from '../ripple.directive';

@Component({
  selector: 'demo-ripple-on-button',
  standalone: true,
  imports: [ButtonComponent, RippleDirective],
  template: `
    <button n-button nRipple nRippleColor="rgba(255,255,255,0.6)">Ripple Button</button>
  `,
})
export class RippleOnButtonDemo {}

import { Component } from '@angular/core';
import { RippleDirective } from '../ripple.directive';

@Component({
  selector: 'demo-ripple-unbounded',
  standalone: true,
  imports: [RippleDirective],
  template: `
    <button
      nRipple
      [nRippleUnbounded]="true"
      [nRippleCentered]="true"
      nRippleColor="#6366f1"
      class="bg-muted text-muted-foreground flex h-12 w-12 cursor-pointer items-center justify-center rounded-full text-lg select-none"
      aria-label="Unbounded icon button"
    >
      ♥
    </button>
  `,
})
export class RippleUnboundedDemo {}
